-- Reconstruct institution_grads from local_1.InstitutionGraduationRecords
CREATE VIEW "institution_grads" AS
SELECT
    "local_1"."InstitutionGraduationRecords"."InstitutionId" AS "unitid",
    "local_1"."InstitutionGraduationRecords"."GraduationYear" AS "year",
    "local_1"."InstitutionGraduationRecords"."Gender" AS "gender",
    "local_1"."InstitutionGraduationRecords"."RaceEthnicity" AS "race",
    "local_1"."InstitutionGraduationRecords"."CohortIdentifier" AS "cohort",
    "local_1"."InstitutionGraduationRecords"."GraduatedCohort" AS "grad_cohort",
    "local_1"."InstitutionGraduationRecords"."GraduationCountStandardTerm" AS "grad_100",
    "local_1"."InstitutionGraduationRecords"."GraduationCountExtendedTerm" AS "grad_150",
    "local_1"."InstitutionGraduationRecords"."GraduationRateStandardTerm" AS "grad_100_rate",
    "local_1"."InstitutionGraduationRecords"."GraduationRateExtendedTerm" AS "grad_150_rate"
FROM "local_1"."InstitutionGraduationRecords";

-- Reconstruct state_sector_details from vertical split + row partition on a fragment
CREATE VIEW "state_sector_details" AS
SELECT t0.[stateIdentifier], t4.[StateCode], t4.[StatePostalCode], t0.[educationLevel], t0.[institutionControl], t0.[institutionCount], t3.[counted_percentage], t0.[stateAwardValue], t0.[awardsPerNationalValue], t1.[expected_award_state_value_text], t0.[expectedAwardNationalValue], t0.[stateApprovalValue], t2.[stateApprovalRank], t2.[graduationRateRank], t0.[awardsByRank]
FROM [local_2].[stateSectorAwardsNationalValue] t0
JOIN (
SELECT [state_sector_awards_per_national_schools_1_to_7].[__orig_rowid] AS __orig_rowid, [local_3].[state_sector_awards_per_national_schools_1_to_7].[state_id], [local_3].[state_sector_awards_per_national_schools_1_to_7].[institution_level], [local_3].[state_sector_awards_per_national_schools_1_to_7].[control_type], [local_3].[state_sector_awards_per_national_schools_1_to_7].[schools_count_in_sector], [local_3].[state_sector_awards_per_national_schools_1_to_7].[awards_per_national_value], [local_3].[state_sector_awards_per_national_schools_1_to_7].[expected_award_state_value_text], [local_3].[state_sector_awards_per_national_schools_1_to_7].[expected_award_national_value], [local_3].[state_sector_awards_per_national_schools_1_to_7].[state_approval_value] FROM [local_3].[state_sector_awards_per_national_schools_1_to_7]
UNION
SELECT [state_sector_awards_per_national_schools_7_to_16].[__orig_rowid] AS __orig_rowid, [local_3].[state_sector_awards_per_national_schools_7_to_16].[state_id], [local_3].[state_sector_awards_per_national_schools_7_to_16].[institution_level], [local_3].[state_sector_awards_per_national_schools_7_to_16].[control_type], [local_3].[state_sector_awards_per_national_schools_7_to_16].[schools_count_in_sector], [local_3].[state_sector_awards_per_national_schools_7_to_16].[awards_per_national_value], [local_3].[state_sector_awards_per_national_schools_7_to_16].[expected_award_state_value_text], [local_3].[state_sector_awards_per_national_schools_7_to_16].[expected_award_national_value], [local_3].[state_sector_awards_per_national_schools_7_to_16].[state_approval_value] FROM [local_3].[state_sector_awards_per_national_schools_7_to_16]
UNION
SELECT [state_sector_awards_per_national_schools_gt_16_or_null].[__orig_rowid] AS __orig_rowid, [local_3].[state_sector_awards_per_national_schools_gt_16_or_null].[state_id], [local_3].[state_sector_awards_per_national_schools_gt_16_or_null].[institution_level], [local_3].[state_sector_awards_per_national_schools_gt_16_or_null].[control_type], [local_3].[state_sector_awards_per_national_schools_gt_16_or_null].[schools_count_in_sector], [local_3].[state_sector_awards_per_national_schools_gt_16_or_null].[awards_per_national_value], [local_3].[state_sector_awards_per_national_schools_gt_16_or_null].[expected_award_state_value_text], [local_3].[state_sector_awards_per_national_schools_gt_16_or_null].[expected_award_national_value], [local_3].[state_sector_awards_per_national_schools_gt_16_or_null].[state_approval_value] FROM [local_3].[state_sector_awards_per_national_schools_gt_16_or_null]
UNION
SELECT [state_sector_awards_per_national_schools_lte_1].[__orig_rowid] AS __orig_rowid, [local_3].[state_sector_awards_per_national_schools_lte_1].[state_id], [local_3].[state_sector_awards_per_national_schools_lte_1].[institution_level], [local_3].[state_sector_awards_per_national_schools_lte_1].[control_type], [local_3].[state_sector_awards_per_national_schools_lte_1].[schools_count_in_sector], [local_3].[state_sector_awards_per_national_schools_lte_1].[awards_per_national_value], [local_3].[state_sector_awards_per_national_schools_lte_1].[expected_award_state_value_text], [local_3].[state_sector_awards_per_national_schools_lte_1].[expected_award_national_value], [local_3].[state_sector_awards_per_national_schools_lte_1].[state_approval_value] FROM [local_3].[state_sector_awards_per_national_schools_lte_1]
) t1 ON t0.[__orig_rowid] = t1.[__orig_rowid]
JOIN [local_2].[stateSectorAwardsRankings] t2 ON t0.[__orig_rowid] = t2.[__orig_rowid]
JOIN [local_3].[state_sector_counted_percentage] t3 ON t0.[__orig_rowid] = t3.[__orig_rowid]
JOIN [local_1].[StateSectorProfile] t4 ON t0.[__orig_rowid] = t4.[__orig_rowid];

-- Reconstruct state_sector_grads from local_3.state_sector_graduation_stats
CREATE VIEW "state_sector_grads" AS
SELECT
    "local_3"."state_sector_graduation_stats"."state_id" AS "stateid",
    "local_3"."state_sector_graduation_stats"."state_name" AS "state",
    "local_3"."state_sector_graduation_stats"."state_abbreviation" AS "state_abbr",
