    "local_3"."state_sector_graduation_stats"."cohort_label" AS "cohort",
    "local_3"."state_sector_graduation_stats"."graduation_cohort_label" AS "grad_cohort",
    "local_3"."state_sector_graduation_stats"."grad_within_100_pct" AS "grad_100",
    "local_3"."state_sector_graduation_stats"."grad_within_150_pct" AS "grad_150",
    "local_3"."state_sector_graduation_stats"."grad_within_100_rate" AS "grad_100_rate",
